// parse parses an LLM response string into validated SVOTriples.
// Returns (triples, true) on success, (nil, false) on JSON failure or wrong shape.
func (e *SVOExtractor) parse(raw string, chunkID string) ([]SVOTriple, bool) {
	cleaned := stripFences(raw)
	var rows []map[string]interface{}
	if err := json.Unmarshal([]byte(cleaned), &rows); err != nil {
		// Try top-level array of any â€” if it fails shape check below will catch it.
		var top interface{}
		if err2 := json.Unmarshal([]byte(cleaned), &top); err2 != nil {
			return nil, false
		}
		arr, ok := top.([]interface{})
		if !ok {
			return nil, false
		}
		triples := []SVOTriple{}
		for _, item := range arr {
			row, ok := item.(map[string]interface{})
			if !ok {
				continue
			}
			t, ok := rowToTriple(row, chunkID, e.verbSet)
			if !ok {
				continue
			}
			triples = append(triples, t)
		}
		return triples, true
	}
	triples := []SVOTriple{}
	for _, row := range rows {
		t, ok := rowToTriple(row, chunkID, e.verbSet)
		if !ok {
			continue
		}
		triples = append(triples, t)
	}
	return triples, true
}

// rowToTriple converts a JSON map row into an SVOTriple, validating verb membership.
func rowToTriple(row map[string]interface{}, chunkID string, verbSet map[string]struct{}) (SVOTriple, bool) {
	verb, _ := row["verb"].(string)
	if len(verb) == 0 {
		return SVOTriple{}, false
	}
	if _, ok := verbSet[verb]; !ok {
		return SVOTriple{}, false
	}
	subj, _ := row["subject_id"].(string)
	obj, _ := row["object_id"].(string)
	conf, _ := row["confidence"].(float64)
	if len(subj) == 0 || len(obj) == 0 {
		return SVOTriple{}, false
	}
	return SVOTriple{
		SubjectID:     subj,
		Verb:          verb,
		ObjectID:      obj,
		Confidence:    conf,
		SourceChunkID: chunkID,
	}, true
}

