// parseEntityAnchored parses an entity-anchored LLM response.
// Returns (result, true) on success; (zero, false) on JSON failure or wrong shape.
func (e *SVOExtractor) parseEntityAnchored(raw string, chunkID string, validIDs map[string]struct{}) (EntityAnchoredResult, bool) {
	cleaned := stripFences(raw)
	var top interface{}
	if err := json.Unmarshal([]byte(cleaned), &top); err != nil {
		return EntityAnchoredResult{}, false
	}
	obj, ok := top.(map[string]interface{})
	if !ok {
		return EntityAnchoredResult{}, false
	}
	relDescriptions := map[string]string{}
	if rd, ok := obj["rel_descriptions"]; ok && rd != nil {
		if rdMap, ok := rd.(map[string]interface{}); ok {
			for k, v := range rdMap {
				desc, _ := v.(string)
				if len(strings.TrimSpace(desc)) > 0 {
					relDescriptions[k] = strings.TrimSpace(desc)
				}
			}
		}
	}
	triples := []SVOTriple{}
	if rawTriples, ok := obj["triples"]; ok && rawTriples != nil {
		if tripleArr, ok := rawTriples.([]interface{}); ok {
			for _, item := range tripleArr {
				row, ok := item.(map[string]interface{})
				if !ok {
					continue
				}
				verb, _ := row["verb"].(string)
				subj, _ := row["subject_id"].(string)
				obj_, _ := row["object_id"].(string)
				conf, _ := row["confidence"].(float64)
				if len(verb) == 0 || len(subj) == 0 || len(obj_) == 0 {
					continue
				}
				if _, inSet := e.verbSet[verb]; !inSet {
					continue
				}
				if _, ok := validIDs[subj]; !ok {
					continue
				}
				if _, ok := validIDs[obj_]; !ok {
					continue
				}
				relKey := fmt.Sprintf("%s|%s|%s", subj, verb, obj_)
				desc := relDescriptions[relKey]
				triples = append(triples, SVOTriple{
					SubjectID:     subj,
					Verb:          verb,
					ObjectID:      obj_,
					Confidence:    conf,
					SourceChunkID: chunkID,
					Description:   desc,
				})
			}
		}
	}
	descriptions := map[string]string{}
	if rawDescs, ok := obj["descriptions"]; ok && rawDescs != nil {
		if descMap, ok := rawDescs.(map[string]interface{}); ok {
			for eid, v := range descMap {
				if _, ok := validIDs[eid]; !ok {
					continue
				}
				desc, _ := v.(string)
				if len(strings.TrimSpace(desc)) > 0 {
					descriptions[eid] = strings.TrimSpace(desc)
				}
			}
		}
	}
	aliases := map[string][]string{}
	if rawAliases, ok := obj["aliases"]; ok && rawAliases != nil {
		if aliasMap, ok := rawAliases.(map[string]interface{}); ok {
			for eid, v := range aliasMap {
				if _, ok := validIDs[eid]; !ok {
					continue
				}
				arr, ok := v.([]interface{})
				if !ok {
					continue
				}
				clean := []string{}
				for _, a := range arr {
					s, _ := a.(string)
					if len(strings.TrimSpace(s)) > 0 {
						clean = append(clean, s)
					}
				}
				if len(clean) > 0 {
					aliases[eid] = clean
				}
			}
		}
	}
	return EntityAnchoredResult{
		Triples:         triples,
		Descriptions:    descriptions,
		Aliases:         aliases,
		RelDescriptions: relDescriptions,
	}, true
}

