// NewRelationshipIndex constructs an empty RelationshipIndex.
func NewRelationshipIndex() *RelationshipIndex {
	return &RelationshipIndex{
		bySubject: map[string][]SVOTriple{},
		byObject:  map[string][]SVOTriple{},
	}
}

// Add inserts a triple into both the subject and object indexes.
func (r *RelationshipIndex) Add(triple SVOTriple) {
	r.bySubject[triple.SubjectID] = append(r.bySubject[triple.SubjectID], triple)
	r.byObject[triple.ObjectID] = append(r.byObject[triple.ObjectID], triple)
}

