// LoadRelationshipIndexFromDB loads a RelationshipIndex from the svo_triples table.
// Returns an empty index (not an error) if the table is absent.
// If namespaces is non-nil, only triples from those namespaces are loaded.
func LoadRelationshipIndexFromDB(con DBConn, namespaces *[]string) (*RelationshipIndex, error) {
	idx := NewRelationshipIndex()
	countRow, err := con.QueryOne(
		"SELECT COUNT(*) FROM information_schema.tables WHERE table_name = 'all_svo_triples'",
	)
	if err != nil {
		return idx, nil
	}
	viewExists := false
	if countRow != nil {
		if n, ok := countRow[0].(int64); ok && n > 0 {
			viewExists = true
		}
	}
	table := "svo_triples"
	if viewExists {
		table = "all_svo_triples"
	}
	var rows [][]interface{}
	if namespaces != nil {
		placeholders := []string{}
		for range *namespaces {
			placeholders = append(placeholders, "?")
		}
		query := fmt.Sprintf(
			"SELECT chunk_id, subject_id, verb, object_id, confidence, COALESCE(description, '') FROM %s WHERE namespace IN (%s)",
			table, strings.Join(placeholders, ", "),
		)
		args := make([]interface{}, len(*namespaces))
		for i, ns := range *namespaces {
			args[i] = ns
		}
		rows, err = con.QueryAll(query, args...)
	} else {
		query := fmt.Sprintf(
			"SELECT chunk_id, subject_id, verb, object_id, confidence, COALESCE(description, '') FROM %s",
			table,
		)
		rows, err = con.QueryAll(query)
	}
	if err != nil {
		return idx, nil
	}
	for _, row := range rows {
		chunkID, _ := row[0].(string)
