// parseDescriptions extracts the descriptions map from a raw JSON object,
// keeping only entries whose entity ID is in validIDs and whose value is non-empty.
func parseDescriptions(raw map[string]interface{}, validIDs map[string]struct{}) map[string]string {
	descriptions := map[string]string{}
	rawDescs, ok := raw["descriptions"]
	if !ok || rawDescs == nil {
		return descriptions
	}
	descMap, ok := rawDescs.(map[string]interface{})
	if !ok {
		return descriptions
	}
	for eid, v := range descMap {
		if _, inSet := validIDs[eid]; !inSet {
			continue
		}
		desc, _ := v.(string)
		if len(strings.TrimSpace(desc)) > 0 {
			descriptions[eid] = strings.TrimSpace(desc)
		}
	}
	return descriptions
}

// parseAliases extracts the aliases map from a raw JSON object,
// keeping only entries whose entity ID is in validIDs and whose alias list is non-empty.
func parseAliases(raw map[string]interface{}, validIDs map[string]struct{}) map[string][]string {
	aliases := map[string][]string{}
	rawAliases, ok := raw["aliases"]
	if !ok || rawAliases == nil {
		return aliases
	}
	aliasMap, ok := rawAliases.(map[string]interface{})
	if !ok {
		return aliases
	}
	for eid, v := range aliasMap {
		if _, inSet := validIDs[eid]; !inSet {
			continue
		}
		arr, ok := v.([]interface{})
		if !ok {
			continue
		}
		clean := []string{}
		for _, a := range arr {
			s, _ := a.(string)
			if len(strings.TrimSpace(s)) > 0 {
				clean = append(clean, s)
			}
		}
		if len(clean) > 0 {
			aliases[eid] = clean
		}
	}
	return aliases
}
